// --- Clear Products Cloud Function ---
exports.clearProducts = functions.https.onRequest((req, res) => {
  cors(req, res, async () => {
    try {
      // await isAuthenticatedAdmin(context); // Temporarily commented out

      const productsRef = db.collection('products');
      const snapshot = await productsRef.get();
      
      if (snapshot.empty) {
        res.status(200).json({ message: 'No documents found in "products" collection. Nothing to delete.' });
        return;
      }

      const batch = db.batch();
      snapshot.docs.forEach(doc => {
        batch.delete(doc.ref);
      });
      await batch.commit();
      res.status(200).json({ message: `Successfully deleted ${snapshot.docs.length} documents from "products" collection.` });
    } catch (error) {
      console.error("Error in clearProducts:", error);
      res.status(500).send('An error occurred in clearProducts.');
    }
  });
});

// --- Populate Dishes Cloud Function ---
exports.populateDishes = functions.https.onRequest((req, res) => {
  cors(req, res, async () => {
    try {
      // await isAuthenticatedAdmin(context); // Temporarily commented out for onRequest

      const dishesCollection = db.collection('dishes');
      const batch = db.batch();

      const dishes = [
        {
          name: 'Salade de Chèvre Chaud',
          ingredients: ['salade', 'fromage_chevre', 'pain_de_mie']
        },
        {
          name: 'Yaourt aux Fruits',
          ingredients: ['yaourt_grec', 'pommes_bio']
        }
      ];

      // Get product IDs for the ingredients
      const productsSnapshot = await db.collection('products').get();
      const productIds = {};
      productsSnapshot.forEach(doc => {
        const productName = doc.data().name.toLowerCase();
        if (productName.includes('salade')) {
          productIds['salade'] = doc.id;
        }
        if (productName.includes('chèvre')) {
          productIds['fromage_chevre'] = doc.id;
        }
        if (productName.includes('pain de mie')) {
          productIds['pain_de_mie'] = doc.id;
        }
        if (productName.includes('yaourt')) {
          productIds['yaourt_grec'] = doc.id;
        }
        if (productName.includes('pommes')) {
            productIds['pommes_bio'] = doc.id;
        }
      });

      dishes.forEach(dish => {
        const docRef = dishesCollection.doc();
        const ingredientsWithIds = dish.ingredients.map(ingredient => productIds[ingredient]).filter(id => id);
        batch.set(docRef, { ...dish, ingredients: ingredientsWithIds });
      });

      await batch.commit();
      res.status(200).json({ message: `Successfully added ${dishes.length} test dishes.` });
    } catch (error) {
      console.error("Error in populateDishes:", error);
      res.status(500).send('An error occurred in populateDishes.');
    }
  });
});

// Helper to parse dates from text
function parseDate(text) {
  // Common date formats (DD/MM/YYYY, MM/DD/YYYY, YYYY-MM-DD, DD-MM-YYYY, etc.)
  const dateRegexes = [
    /\b(\d{1,2})[./-](\d{1,2})[./-](\d{4})\b/, // DD/MM/YYYY or DD-MM-YYYY
    /\b(\d{4})[./-](\d{1,2})[./-](\d{1,2})\b/, // YYYY-MM-DD
    /\b(\d{1,2})[./-](Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec)[./-](\d{4})\b/i, // DD-MON-YYYY
    /\b(Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec)[./-](\d{1,2})[./-](\d{4})\b/i, // MON-DD-YYYY
  ];

  for (const regex of dateRegexes) {
    const match = text.match(regex);
    if (match) {
      // Basic parsing, can be improved for ambiguity (e.g., MM/DD vs DD/MM)
      try {
        let dateCandidate;
        if (match[3].length === 4) { // YYYY is present
          dateCandidate = new Date(`${match[1]}-${match[2]}-${match[3]}`); // Assuming MM-DD-YYYY or DD-MM-YYYY
        } else { // Assuming DD/MM or MM/DD without year, default to current year
          const currentYear = new Date().getFullYear();
          dateCandidate = new Date(`${match[1]}-${match[2]}-${currentYear}`);
        }
        
        // Check if date is valid
        if (!isNaN(dateCandidate.getTime())) {
          return dateCandidate.toISOString().split('T')[0]; // Return in YYYY-MM-DD format
        }
      } catch (e) {
        console.warn("Failed to parse date candidate:", match.join('-'), e);
      }
    }
  }
  return null;
}

// --- OCR Cloud Function to extract Expiry Date from Image ---
exports.extractExpiryDateFromImage = functions.https.onCall(async (data, context) => {
  try {
    functions.logger.log('Received data:', data); // Add this line
    // Check authentication if needed (admin or specific user)
    // await isAuthenticatedAdmin(context); // Uncomment if only admins can use OCR

    const base64Image = data.image; // Expecting base64 image data
    if (!base64Image) {
      throw new functions.https.HttpsError('invalid-argument', 'No image data provided.');
    }

    const imageBuffer = Buffer.from(base64Image, 'base64');

    const [result] = await visionClient.textDetection({ // Changed client to visionClient
      image: { content: imageBuffer },
    });
    const detections = result.textAnnotations;

    if (!detections || detections.length === 0) {
      return { expiryDate: null, message: 'No text detected in the image.' };
    }

    const fullText = detections[0].description; // The first annotation is the full text
    functions.logger.log('Full text detected:', fullText);

    const detectedDate = parseDate(fullText);

    if (detectedDate) {
      return { expiryDate: detectedDate, message: 'Expiry date detected.' };
    } else {
      return { expiryDate: null, message: 'No valid expiry date found in the text.' };
    }

  } catch (error) {
    functions.logger.error("Error in extractExpiryDateFromImage:", error);
    throw new functions.https.HttpsError('internal', 'An error occurred during OCR processing.', error.message);
  }
});

import { useState } from 'react';
import { Settings, RefreshCw, Trash2, PackagePlus } from 'lucide-react';
import { resetDatabase, emptyDatabase } from '../firebase/dbActions';
import Card from './Card';

export default function AdminPanel() {
  const [tableCount, setTableCount] = useState(4);
  const [isUpdating, setIsUpdating] = useState(false);
  const [isEmptying, setIsEmptying] = useState(false);
  const [isPopulatingProducts, setIsPopulatingProducts] = useState(false);
  const [isClearingProducts, setIsClearingProducts] = useState(false);
  const [productFeedback, setProductFeedback] = useState('');
  const [isPopulatingDishes, setIsPopulatingDishes] = useState(false);
  const [dishesFeedback, setDishesFeedback] = useState('');

  const cloudFunctionsBaseUrl = `https://us-central1-${import.meta.env.VITE_FIREBASE_PROJECT_ID}.cloudfunctions.net`;

  const handleReset = async () => {
    setIsUpdating(true);
    try {
      await resetDatabase(tableCount);
    } catch {
      alert("Erreur lors de la mise à jour");
    } finally {
      setIsUpdating(false);
    }
  };

  const handleEmpty = async () => {
    if (!confirm("Êtes-vous sûr de vouloir vider complètement la base de données ? Cette action est irréversible.")) {
      return;
    }
    setIsEmptying(true);
    try {
      await emptyDatabase();
      alert("Base de données vidée avec succès.");
    } catch {
      alert("Erreur lors du vidage de la base de données");
    }
    finally {
      setIsEmptying(false);
    }
  };

  const handlePopulateProducts = async () => {
      setIsPopulatingProducts(true);
      setProductFeedback('Remplissage des produits de test...');
      
      try {
        const response = await fetch(`${cloudFunctionsBaseUrl}/populateProducts`, { method: 'POST' });
        if (!response.ok) {
          throw new Error(`HTTP error! status: ${response.status}`);
        }
        const result = await response.json();
        setProductFeedback(result.message || 'Produits de test ajoutés avec succès !');
      } catch (error) {
          console.error("Error populating products:", error);
          setProductFeedback(`Erreur lors du remplissage des produits: ${error.message}`);
      } finally {
          setIsPopulatingProducts(false);
          setTimeout(() => setProductFeedback(''), 3000);
      }
  };

  const handleClearProducts = async () => {
      if (!confirm("Êtes-vous sûr de vouloir vider la collection de produits ? Cette action est irréversible.")) {
          return;
      }
      setIsClearingProducts(true);
      setProductFeedback('Vidage de la collection de produits...');
      
      try {
        const response = await fetch(`${cloudFunctionsBaseUrl}/clearProducts`, { method: 'POST' });
        if (!response.ok) {
          throw new Error(`HTTP error! status: ${response.status}`);
        }
        const result = await response.json();
        setProductFeedback(result.message || 'Collection de produits vidée avec succès.');
      } catch (error) {
          console.error("Error clearing products:", error);
          setProductFeedback(`Erreur lors du vidage des produits: ${error.message}`);
      } finally {
          setIsClearingProducts(false);
          setTimeout(() => setProductFeedback(''), 3000);
      }
  };

  const handlePopulateDishes = async () => {
      setIsPopulatingDishes(true);
      setDishesFeedback('Remplissage des plats de test...');
      
      try {
        const response = await fetch(`${cloudFunctionsBaseUrl}/populateDishes`, { method: 'POST' });
        if (!response.ok) {
          throw new Error(`HTTP error! status: ${response.status}`);
        }
        const result = await response.json();
        setDishesFeedback(result.message || 'Plats de test ajoutés avec succès !');
      } catch (error) {
          console.error("Error populating dishes:", error);
          setDishesFeedback(`Erreur lors du remplissage des plats: ${error.message}`);
      } finally {
          setIsPopulatingDishes(false);
          setTimeout(() => setDishesFeedback(''), 3000);
      }
  };

  return (
    <Card title="Configuration Système" titleIcon={<Settings />}>
      <div className="flex items-end gap-4 mb-4">
        <div className="flex-1">
          <label className="block text-gray-500 text-[9px] uppercase mb-1">Nombre de tables en salle</label>
          <input 
            type="number" 
            value={tableCount}
            onChange={(e) => setTableCount(e.target.value)}
            className="w-full bg-black border border-gray-800 rounded p-2 text-white outline-none focus:border-mictlan-gold"
            min="1"
            max="50"
          />
        </div>
        
        <button 
          onClick={handleReset}
          disabled={isUpdating}
          className="bg-black/40 text-gray-500 rounded-lg border border-gray-800 hover:text-mictlan-gold transition-all px-4 py-2 font-bold text-[10px] uppercase flex items-center gap-2"
        >
          <RefreshCw className={`w-3 h-3 ${isUpdating ? 'animate-spin' : ''}`} />
          {isUpdating ? 'Mise à jour...' : 'Réinitialiser Salle'}
        </button>
        <button 
          onClick={handleEmpty}
          disabled={isEmptying}
          className="bg-black/40 text-gray-500 rounded-lg border border-gray-800 hover:text-mictlan-gold transition-all px-4 py-2 font-bold text-[10px] uppercase flex items-center gap-2"
        >
          <Trash2 className={`w-3 h-3 ${isEmptying ? 'animate-spin' : ''}`} />
          {isEmptying ? 'Vidage...' : 'Vider DB'}
        </button>
      </div>
      <p className="text-[8px] text-gray-600 mt-2 italic font-mono uppercase">
        * Réinitialiser Salle : Efface toutes les données actuelles pour générer {tableCount} tables. Vider DB : Supprime toutes les données des collections connues (tables, inventory, logs, users). Pour vider toutes les collections inconnues, exécutez `npm run empty-db` or `node empty-db.cjs` dans un terminal.
      </p>

      <div className="flex flex-col gap-4 mb-4 mt-4 border-t border-gray-700 pt-4">
        <label className="block text-sm font-black text-mictlan-gold uppercase tracking-[0.2em] mb-2">
          Gestion des Produits de Test
        </label>
        <div className="flex gap-4">
          <button 
            onClick={handlePopulateProducts}
            disabled={isPopulatingProducts}
            className="flex-1 bg-black/40 text-gray-500 rounded-lg border border-gray-800 hover:text-mictlan-gold transition-all px-4 py-2 font-bold text-[10px] uppercase flex items-center justify-center gap-2"
          >
            <PackagePlus className={`w-3 h-3 ${isPopulatingProducts ? 'animate-spin' : ''}`} />
            {isPopulatingProducts ? 'Remplissage...' : 'Remplir Produits'}
          </button>
          <button 
            onClick={handleClearProducts}
            disabled={isClearingProducts}
            className="flex-1 bg-black/40 text-gray-500 rounded-lg border border-gray-800 hover:text-mictlan-red transition-all px-4 py-2 font-bold text-[10px] uppercase flex items-center justify-center gap-2"
          >
            <Trash2 className={`w-3 h-3 ${isClearingProducts ? 'animate-spin' : ''}`} />
            {isClearingProducts ? 'Vidage...' : 'Vider Produits'}
          </button>
        </div>
        {productFeedback && <p className="text-[10px] text-center text-mictlan-gold mt-2">{productFeedback}</p>}
      </div>

      <div className="flex flex-col gap-4 mb-4 mt-4 border-t border-gray-700 pt-4">
        <label className="block text-sm font-black text-mictlan-gold uppercase tracking-[0.2em] mb-2">
          Gestion des Plats de Test
        </label>
        <div className="flex gap-4">
          <button 
            onClick={handlePopulateDishes}
            disabled={isPopulatingDishes}
            className="flex-1 bg-black/40 text-gray-500 rounded-lg border border-gray-800 hover:text-mictlan-gold transition-all px-4 py-2 font-bold text-[10px] uppercase flex items-center justify-center gap-2"
          >
            <PackagePlus className={`w-3 h-3 ${isPopulatingDishes ? 'animate-spin' : ''}`} />
            {isPopulatingDishes ? 'Remplissage...' : 'Remplir Plats'}
          </button>
        </div>
        {dishesFeedback && <p className="text-[10px] text-center text-mictlan-gold mt-2">{dishesFeedback}</p>}
      </div>
    </Card>
  );
}

